import React, { useState, useEffect } from 'react';

const App = () => {
  const [menu, setMenu] = useState([]);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch(`http://localhost:8000/menu/${date}`)
      .then(res => res.json())
      .then(data => {
        setMenu(data);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  }, [date]);

  if (loading) return <div className="p-8 text-center">Loading menu...</div>;

  return (
    <div className="max-w-4xl mx-auto p-4 font-sans">
      <h1 className="text-3xl font-bold text-center mb-8 text-blue-600">Canteen Food Rating</h1>

      <div className="flex justify-center mb-8">
        <input 
          type="date" 
          value={date} 
          onChange={(e) => setDate(e.target.value)}
          className="border p-2 rounded shadow-sm"
        />
      </div>

      {menu.length === 0 ? (
        <p className="text-center text-gray-500">No menu found for this date.</p>
      ) : (
        <div className="grid gap-6">
          {menu.map(meal => (
            <MealCard key={meal.id} meal={meal} />
          ))}
        </div>
      )}
    </div>
  );
};

const MealCard = ({ meal }) => {
  const [rating, setRating] = useState(0);
  const [comment, setComment] = useState('');
  const [userName, setUserName] = useState('');
  const [submitted, setSubmitted] = useState(false);

  const submitRating = async () => {
    await fetch('http://localhost:8000/rate', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        meal_id: meal.id,
        rating,
        comment,
        user_name: userName
      })
    });
    setSubmitted(true);
  };

  return (
    <div className="border p-6 rounded-lg shadow-md bg-white hover:shadow-lg transition-shadow">
      <div className="flex justify-between items-start mb-4">
        <div>
          <span className="text-xs font-semibold uppercase px-2 py-1 bg-blue-100 text-blue-800 rounded mr-2">
            {meal.type}
          </span>
          <h3 className="text-xl font-bold mt-2">{meal.name}</h3>
        </div>
        <span className="text-sm text-gray-500">{meal.mensa}</span>
      </div>

      {!submitted ? (
        <div className="space-y-4">
          <div className="flex gap-2 text-2xl">
            {[1, 2, 3, 4, 5].map(star => (
              <button 
                key={star} 
                onClick={() => setRating(star)}
                className={`transition-colors ${rating >= star ? 'text-yellow-400' : 'text-gray-300'}`}
              >
                ★
              </button>
            ))}
          </div>
          <input 
            placeholder="Your name (optional)" 
            className="w-full border p-2 rounded"
            value={userName}
            onChange={(e) => setUserName(e.target.value)}
          />
          <textarea 
            placeholder="What did you think?" 
            className="w-full border p-2 rounded"
            value={comment}
            onChange={(e) => setComment(e.target.value)}
          />
          <button 
            onClick={submitRating}
            className="w-full bg-blue-600 text-white py-2 rounded font-bold hover:bg-blue-700 transition-colors"
          >
            Submit Rating
          </button>
        </div>
      ) : (
        <div className="text-center text-green-600 font-medium py-4">
          Thank you for your rating!
        </div>
      )}
    </div>
  );
};

export default App;
